-- Data for `resumes_resume`
INSERT INTO `resumes_resume` (`id`, `title`, `resume_data`, `pdf_file`, `status`, `error_message`, `created_at`, `updated_at`, `template_id`, `user_id`) VALUES (7, '李浩然的简历', '{\"skills\": [\"全国计算机等级考试二级（Java）\", \"英语四级（CET-4），成绩 521 分\", \"软考初级（程序员）\"], \"personal\": {\"name\": \"李浩然\", \"email\": \"lihaoran_dev@163.com\", \"phone\": \"13564896516\", \"photo\": \"data:image/png;base64,\", \"summary\": \"计算机科学与技术专业本科，在校期间系统学习了数据结构、计算机网络、数据库原理等核心课程。熟练掌握 Java、Spring Boot、MyBatis 等后端技术栈，以及 Vue.js 前端框架。主导开发了家政服务平台等多个项目，具备从需求分析到系统部署的全流程开发能力。拥有良好的代码规范和团队协作意识，善于通过技术手段解决实际业务问题。\", \"position\": \"Java 开发工程师 / 后端开发工程师\"}, \"projects\": [{\"name\": \"家政服务平台（毕业设计）\", \"role\": \"全栈开发负责人\", \"period\": \"2023.11-2024.01\", \"description\": \"该项目是一个面向家庭用户和家政服务人员的 O2O 平台，旨在解决传统家政服务信息不对称、流程不透明的问题。\\n技术栈：Spring Boot、MyBatis、MySQL、Redis、Vue.js、Element UI。\\n核心功能：用户注册登录、服务分类浏览、在线下单支付、订单状态跟踪、服务评价、后台管理等。\\n个人贡献：\\n负责后端整体架构设计，实现了 RESTful API 接口，确保了系统的可扩展性和可维护性。\\n设计并实现了 MySQL 数据库表结构，使用 Redis 缓存热门服务和用户会话，提升了系统响应速度。\\n独立开发了前端用户端和管理员端的核心页面，实现了响应式布局，适配移动端和 PC 端。\\n完成了项目的部署和上线，使用 Nginx 作为反向代理，部署在阿里云 ECS 服务器上。\"}], \"education\": [{\"major\": \"计算机科学与技术\", \"degree\": \"本科\", \"period\": \"2020.09-2024.06\", \"school\": \"鹤壁工业大学\"}], \"experience\": [{\"period\": \"2023.07-2023.10\", \"company\": \"计算机信息技术有限公司\", \"position\": \"Java 开发实习生\", \"description\": \"参与企业内部 OA 系统的后端开发，使用 Spring Boot + MyBatis 框架实现了员工考勤、报销审批等模块，日均处理请求约 5000 次。\\n负责接口文档的编写与维护，使用 Swagger 生成在线文档，提升了前后端协作效率。\\n协助进行数据库优化，通过添加索引和优化 SQL 语句，将关键报表查询时间从 12 秒缩短至 2 秒。\\n参与每日站会和代码评审，学习并遵循团队的开发规范和 Git 工作流。\"}]}', '', 'draft', '', '2026-03-19 13:52:44.342899', '2026-03-19 13:52:44.342899', 13, 1);

