INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (4, '简约典藏', '纸张质感的典藏风，适合稳重型简历展示。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f4efe6; color: #4f4237; }\n        .shell { background: #ffffff; border: 1px solid #d8c8b8; }\n        .hero { background: #fffdfa; color: #2d241d; padding: 28px 34px 24px; }\n        .hero-kicker { font-size: 13px; letter-spacing: 5px; color: #8b5e3c; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 10px; margin: 0 0 16px; }\n        .body { padding: 24px 34px 30px; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; color: #2d241d; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #8b5e3c; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 128px; object-fit: cover; border: 3px solid #d8c8b8; background: #ffffff; border-radius: 18px; }\n        .section { margin-bottom: 24px; }\n        .section h2 { font-size: 18px; margin: 0 0 12px; color: #5e4028; letter-spacing: 3px; border-left: 6px solid #8b5e3c; padding-left: 10px; border-bottom: 1px solid #e5d7c6; padding-bottom: 6px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #2d241d; }\n        .item-date { float: right; color: #8a7666; font-size: 12px; background: #f7efe7; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #6b5747; font-size: 13px; margin: 4px 0; }\n        .item-content { color: #4f4237; font-size: 13px; line-height: 1.8; }\n        .skills { color: #4f4237; font-size: 13px; line-height: 1.8; }\n    </style>\n</head>\n<body>\n    <div class=\"shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CURATED RESUME</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{personal_info_html}}\n        </div>\n        <div class=\"body\">\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 02:23:57.162720', '2026-03-19 09:56:02.723209', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (5, '专业锋线', '利落的深蓝职业风，信息层级清晰，适合校招与社招。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #eef3f8; color: #33485c; }\n        .shell { background: #ffffff; border: 1px solid #c7d7ea; }\n        .hero { background: #15324c; color: #ffffff; padding: 28px 34px 24px; }\n        .hero-kicker { font-size: 13px; letter-spacing: 5px; color: #9dc0e5; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 10px; margin: 0 0 16px; }\n        .body { padding: 24px 34px 30px; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; color: #ffffff; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #cfe1f3; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 128px; object-fit: cover; border: 3px solid #d8e6f5; background: #ffffff; border-radius: 14px; }\n        .section { margin-bottom: 24px; }\n        .section h2 { font-size: 18px; margin: 0 0 12px; color: #15324c; letter-spacing: 3px; border-left: 6px solid #3f86d9; padding-left: 10px; border-bottom: 1px solid #dce8f4; padding-bottom: 6px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #15324c; }\n        .item-date { float: right; color: #6c84a0; font-size: 12px; background: #edf4fb; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #47607a; font-size: 13px; margin: 4px 0; }\n        .item-content { color: #33485c; font-size: 13px; line-height: 1.8; }\n        .skills { color: #33485c; font-size: 13px; line-height: 1.8; }\n    </style>\n</head>\n<body>\n    <div class=\"shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">PROFESSIONAL PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{personal_info_html}}\n        </div>\n        <div class=\"body\">\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 02:23:57.254771', '2026-03-19 09:56:02.819531', 1);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (6, '创意秀场', '海报感更强的创意模板，强调艺术字标题和色彩对比。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fff7ef; color: #5b4450; }\n        .shell { background: #ffffff; border: 1px solid #f0d7c0; }\n        .hero { background: #a33c5d; color: #fff7ef; padding: 28px 34px 24px; }\n        .hero-kicker { font-size: 13px; letter-spacing: 5px; color: #ffd8b0; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 10px; margin: 0 0 16px; }\n        .body { padding: 24px 34px 30px; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; color: #fff7ef; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #ffd8b0; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 128px; object-fit: cover; border: 3px solid rgba(255, 216, 176, 0.85); background: #ffffff; border-radius: 14px; }\n        .section { margin-bottom: 24px; }\n        .section h2 { font-size: 18px; margin: 0 0 12px; color: #a33c5d; letter-spacing: 3px; border-left: 6px solid #f3a65a; padding-left: 10px; border-bottom: 1px solid #f5dfcd; padding-bottom: 6px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #7c2744; }\n        .item-date { float: right; color: #d18652; font-size: 12px; background: #fff2e4; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #90546c; font-size: 13px; margin: 4px 0; }\n        .item-content { colo