INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (7, '湖蓝侧栏', '左侧资料栏加右侧正文区，适合信息密度更高的简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #eef6fb; color: #425565; }\n        .shell { display: flex; background: #ffffff; border: 1px solid #d2e5f2; min-height: 960px; }\n        .sidebar { width: 260px; background: #2e6287; color: #f7fbff; padding: 34px 24px; }\n        .main { flex: 1; padding: 30px 34px; background: #ffffff; }\n        .sidebar-kicker { font-size: 12px; letter-spacing: 4px; color: #b8d8ec; margin-bottom: 10px; }\n        .sidebar-name { font-size: 30px; font-weight: bold; letter-spacing: 6px; margin: 0 0 20px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-info tr { display: block; }\n        .sidebar .personal-meta,\n        .sidebar .personal-photo-wrap { display: block; width: 100%; text-align: left; padding: 0; }\n        .sidebar .personal-row { margin: 0 0 8px; font-size: 13px; line-height: 1.7; color: #f7fbff; }\n        .sidebar .personal-label { display: inline-block; min-width: 76px; font-weight: bold; color: #b8d8ec; }\n        .sidebar .personal-photo-wrap { margin-top: 18px; }\n        .sidebar .personal-photo { width: 92px; height: 92px; object-fit: cover; border-radius: 50%; border: 4px solid #d6e8f4; background: #ffffff; }\n        .section { margin-bottom: 24px; }\n        .section h2 { font-size: 17px; margin: 0 0 12px; color: #2e6287; border-bottom: 1px solid #d9e7f1; padding-bottom: 8px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; padding-left: 2px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #244961; }\n        .item-date { float: right; color: #7192ab; font-size: 12px; }\n        .item-subtitle { color: #537187; font-size: 13px; margin: 4px 0; }\n        .item-content { color: #425565; font-size: 13px; line-height: 1.8; }\n        .skills { color: #425565; font-size: 13px; line-height: 1.8; }\n    </style>\n</head>\n<body>\n    <div class=\"shell\">\n        <aside class=\"sidebar\">\n            <div class=\"sidebar-kicker\">LAKE BLUE</div>\n            <div class=\"sidebar-name\">{{name}}</div>\n            {{personal_info_html}}\n        </aside>\n        <main class=\"main\">\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </main>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 09:54:34.230097', '2026-03-19 09:56:03.353604', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (8, '森屿圆像', '深绿左栏搭配圆形头像，更适合沉稳自然风格。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\">\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #edf4ef; color: #43584e; }\n        .shell { display: flex; background: #ffffff; border: 1px solid #d1dfd5; min-height: 960px; }\n        .sidebar { width: 260px; background: #2e5a48; color: #f5faf7; padding: 34px 24px; }\n        .main { flex: 1; padding: 30px 34px; background: #ffffff; }\n        .sidebar-kicker { font-size: 12px; letter-spacing: 4px; color: #b8d7ca; margin-bottom: 10px; }\n        .sidebar-name { font-size: 30px; font-weight: bold; letter-spacing: 6px; margin: 0 0 20px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-info tr { display: block; }\n        .sidebar .personal-meta,\n        .sidebar .personal-photo-wrap { display: block; width: 100%; text-align: left; padding: 0; }\n        .sidebar .personal-row { margin: 0 0 8px; font-size: 13px; line-height: 1.7; color: #f5faf7; }\n        .sidebar .personal-label { display: inline-block; min-width: 76px; font-weight: bold; color: #c7e1d5; }\n        .sidebar .personal-photo-wrap { margin-top: 18px; }\n        .sidebar .personal-photo { width: 92px; height: 92px; object-fit: cover; border-radius: 50%; border: 4px solid #d5e7de; background: #ffffff; }\n        .section { margin-bottom: 24px; }\n        .section h2 { font-size: 17px; margin: 0 0 12px; color: #2e5a48; border-bottom: 1px solid #dde9e2; padding-bottom: 8px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; padding-left: 2px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #2f4e40; }\n        .item-date { float: right; color: #759685; font-size: 12px; }\n        .item-subtitle { color: 