INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (16, '鎏金序章', '奶油金与墨色对比的封面式简历，强调大标题和稳重质感。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f6efe5; color: #4b3c2d; }\n        .resume-shell { background: #fffdf9; border: 1px solid #e7d4b0; }\n        .hero { padding: 28px 34px 22px; background: #fff8ec; color: #2d241c; border-bottom: 4px solid #bb8a3d; }\n        .hero-kicker { font-size: 12px; letter-spacing: 4px; color: #bb8a3d; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 8px; margin: 0 0 8px; text-shadow: 2px 2px 0 #ead4aa; }\n        .hero-role { display: inline-block; padding: 4px 14px; border-radius: 999px; border: 1px solid #bb8a3d; color: #7a5624; background: #fbf2dc; font-size: 12px; }\n        .content { padding: 24px 34px 30px; }\n        .personal-card { margin-bottom: 20px; padding: 16px 18px; background: #fff5e6; border-left: 6px solid #bb8a3d; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #7a5624; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 22px; border: 3px solid #ead4aa; background: #ffffff; }\n        .section { margin-bottom: 20px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #e7d4b0; color: #7a5624; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #2d241c; }\n        .item-date { float: right; color: #967f63; font-size: 12px; background: #fbf2dc; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #76614a; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #4b3c2d; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.301197', '2026-03-19 14:31:20.301197', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (17, '薄荷留白', '清爽薄荷绿配合留白布局，适合校招和轻职业风格。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #eef8f4; color: #35554c; }\n        .resume-shell { background: #ffffff; border: 1px solid #d3ebe2; }\n        .hero { padding: 28px 34px 22px; background: #f6fffb; color: #213a33; border-bottom: 4px solid #4ba58a; }\n        .hero-kicker { font-size: 12px; letter-spacing: 4px; color: #4ba58a; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 8px; margin: 0 0 8px; text-shadow: 2px 2px 0 #bde5d9; }\n        .hero-role { display: inline-block; padding: 4px 14px; border-radius: 999px; border: 1px solid #4ba58a; color: #2d7863; background: #ecfaf5; font-size: 12px; }\n        .content { padding: 24px 34px 30px; }\n        .personal-card { margin-bottom: 20px; padding: 16px 18px; background: #f2fbf7; border-left: 6px solid #4ba58a; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #2d7863; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 50%; border: 3px solid #bde5d9; background: #ffffff; }\n        .section { margin-bottom: 20px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #d3ebe2; color: #2d7863; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #213a33; }\n        .item-date { float: right; color: #7c9b92; font-size: 12px; background: #ecfaf5; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #5a7a71; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #35554c; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.430771', '2026-03-19 14:31:20.430771', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (18, '雾蓝视界', '雾蓝编辑部风格，版式拉开层次，整体轻盈克制。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #eef4fb; color: #334864; }\n        .resume-shell { background: #ffffff; border: 1px solid #dbe5f4; }\n        .banner { padding: 26px 32px 20px; background: #f7faff; border-left: 14px solid #5d84c3; }\n        .banner-label { font-size: 12px; letter-spacing: 5px; color: #335a99; margin-bottom: 8px; }\n        .banner-name { font-size: 33px; font-weight: bold; letter-spacing: 6px; margin: 0 0 8px; color: #1f2e45; }\n        .banner-role { color: #556b89; font-size: 14px; }\n        .body { padding: 22px 32px 28px; }\n        .personal-band { margin-bottom: 18px; padding: 14px 18px; background: #f5f8fd; border-top: 2px solid #5d84c3; border-bottom: 2px solid #5d84c3; }\n        .personal-band .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #335a99; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 18px; border: 3px solid #bfd0ee; background: #ffffff; }\n        .section { margin-bottom: 18px; padding-left: 16px; border-left: 4px solid #bfd0ee; }\n        .section h2 { margin: 0 0 10px; color: #335a99; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #1f2e45; }\n        .item-date { float: right; color: #7d8fa8; font-size: 12px; }\n        .item-subtitle { color: #556b89; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #334864; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"banner\">\n            <div class=\"banner-label\">EDITORIAL CV</div>\n            <div class=\"banner-name\">{{name}}</div>\n            {{#if position}}<div class=\"banner-role\">应聘职位：{{position}}</div>{{/if}}\n        </div>\n        <div class=\"body\">\n            <div class=\"personal-band\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.438021', '2026-03-19 14:31:20.438021', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (19, '绯红焦点', '高对比绯红卡片布局，信息模块清晰，适合希望突出个人风格的简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fff5f5; color: #583840; }\n        .resume-shell { background: #fffdfd; border: 1px solid #f0d9df; }\n        .masthead { padding: 24px 30px; background: #fff8fa; border-bottom: 1px solid #f0d9df; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #cf4c66; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #3c2028; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #fff0f4; color: #9f3248; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #fff6f8; border: 1px solid #f0d9df; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #9f3248; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #f1b6c3; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #f0d9df; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #9f3248; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #3c2028; }\n        .item-date { float: right; color: #9d7480; font-size: 12px; background: #fff0f4; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #84505c; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #583840; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.458002', '2026-03-19 14:31:20.458002', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (20, '云杉影像', '深绿左栏搭配摄影感主区，更适合沉稳型求职者。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #eef3ef; color: #32453a; }\n        .resume-shell { background: #ffffff; border: 1px solid #d8e3db; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .sidebar { width: 31%; background: #3f5f49; color: #eef6f0; padding: 28px 24px; vertical-align: top; }\n        .main { padding: 28px 28px 24px; vertical-align: top; }\n        .side-kicker { font-size: 12px; letter-spacing: 4px; color: #adcab4; margin-bottom: 8px; }\n        .side-name { font-size: 28px; font-weight: bold; letter-spacing: 6px; margin: 0 0 10px; color: #eef6f0; }\n        .side-role { display: inline-block; padding: 5px 12px; border-radius: 999px; border: 1px solid #adcab4; color: #eef6f0; font-size: 12px; margin-bottom: 18px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #adcab4; }\n        .sidebar .personal-value { color: #eef6f0; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #adcab4; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-left: 10px; border-left: 5px solid #4f7f63; color: #355340; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #1d2b22; }\n        .item-date { float: right; color: #809084; font-size: 12px; }\n        .item-subtitle { color: #5a6d60; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #32453a; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"sidebar\">\n                    <div class=\"side-kicker\">SELECTED RESUME</div>\n                    <div class=\"side-name\">{{name}}</div>\n                    {{#if position}}<div class=\"side-role\">{{position}}</div>{{/if}}\n                    {{personal_info_html}}\n                </td>\n                <td class=\"main\">\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.477986', '2026-03-19 14:31:20.477986', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (21, '珊瑚叙事', '暖珊瑚右栏与柔和正文区结合，视觉更亲和。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #fff7f3; color: #58433b; }\n        .resume-shell { background: #ffffff; border: 1px solid #f1ddd6; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .main { width: 68%; padding: 28px 28px 24px; vertical-align: top; }\n        .sidebar { background: #d98266; color: #fff8f6; padding: 28px 24px; vertical-align: top; }\n        .headline { margin-bottom: 18px; padding-bottom: 12px; border-bottom: 2px solid #f3c7bb; }\n        .headline-kicker { font-size: 12px; color: #d98266; letter-spacing: 4px; margin-bottom: 8px; }\n        .headline-name { font-size: 30px; font-weight: bold; letter-spacing: 7px; margin: 0 0 8px; color: #38231d; }\n        .headline-role { display: inline-block; padding: 4px 12px; border-radius: 999px; background: #fff1eb; color: #b05b42; font-size: 12px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #ffe1d7; }\n        .sidebar .personal-value { color: #fff8f6; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 20px; border: 4px solid #ffe1d7; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #f1ddd6; color: #b05b42; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #38231d; }\n        .item-date { float: right; color: #a6877c; font-size: 12px; }\n        .item-subtitle { color: #8a6558; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #58433b; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"main\">\n                    <div class=\"headline\">\n                        <div class=\"headline-kicker\">PORTFOLIO RESUME</div>\n                        <div class=\"headline-name\">{{name}}</div>\n                        {{#if position}}<div class=\"headline-role\">{{position}}</div>{{/if}}\n                    </div>\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n                <td class=\"sidebar\">\n                    {{personal_info_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.502492', '2026-03-19 14:31:20.502492', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (22, '墨蓝格调', '蓝黑双色分栏，结构硬朗，适合产品、运营、技术岗位。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #eef3f8; color: #334658; }\n        .resume-shell { background: #ffffff; border: 1px solid #d7e2ee; }\n        .masthead { padding: 24px 30px; background: #f8fbfe; border-bottom: 1px solid #d7e2ee; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #486c92; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #162636; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #edf4fb; color: #274662; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #f4f8fb; border: 1px solid #d7e2ee; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #274662; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 16px; border: 4px solid #b9ccdf; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #d7e2ee; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #274662; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #162636; }\n        .item-date { float: right; color: #7b8d9d; font-size: 12px; background: #edf4fb; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #55697c; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #334658; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.523722', '2026-03-19 14:31:20.523722', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (23, '霞光履历', '日落橙与暖白组合，封面感更强，适合市场与新媒体岗位。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fff3eb; color: #5a4330; }\n        .resume-shell { background: #fffefc; border: 1px solid #eed9c2; }\n        .hero { padding: 28px 34px 22px; background: #fff8f0; color: #392818; border-bottom: 4px solid #de8b45; }\n        .hero-kicker { font-size: 12px; letter-spacing: 4px; color: #de8b45; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 8px; margin: 0 0 8px; text-shadow: 2px 2px 0 #f4cfaa; }\n        .hero-role { display: inline-block; padding: 4px 14px; border-radius: 999px; border: 1px solid #de8b45; color: #9e5f28; background: #fff4e8; font-size: 12px; }\n        .content { padding: 24px 34px 30px; }\n        .personal-card { margin-bottom: 20px; padding: 16px 18px; background: #fff5ea; border-left: 6px solid #de8b45; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #9e5f28; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 50%; border: 3px solid #f4cfaa; background: #ffffff; }\n        .section { margin-bottom: 20px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #eed9c2; color: #9e5f28; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #392818; }\n        .item-date { float: right; color: #a2836e; font-size: 12px; background: #fff4e8; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #866851; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #5a4330; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.539115', '2026-03-19 14:31:20.539115', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (24, '青藤方舟', '草木感双栏布局，头像圆框更柔和，适合教育、设计方向。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #f1f6f0; color: #3f4d36; }\n        .resume-shell { background: #ffffff; border: 1px solid #dde8d6; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .sidebar { width: 31%; background: #597441; color: #f7fbf2; padding: 28px 24px; vertical-align: top; }\n        .main { padding: 28px 28px 24px; vertical-align: top; }\n        .side-kicker { font-size: 12px; letter-spacing: 4px; color: #dbe7ce; margin-bottom: 8px; }\n        .side-name { font-size: 28px; font-weight: bold; letter-spacing: 6px; margin: 0 0 10px; color: #f7fbf2; }\n        .side-role { display: inline-block; padding: 5px 12px; border-radius: 999px; border: 1px solid #dbe7ce; color: #f7fbf2; font-size: 12px; margin-bottom: 18px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #dbe7ce; }\n        .sidebar .personal-value { color: #f7fbf2; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #dbe7ce; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-left: 10px; border-left: 5px solid #6f8e53; color: #4b6435; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #26311e; }\n        .item-date { float: right; color: #88967d; font-size: 12px; }\n        .item-subtitle { color: #66755a; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #3f4d36; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"sidebar\">\n                    <div class=\"side-kicker\">SELECTED RESUME</div>\n                    <div class=\"side-name\">{{name}}</div>\n                    {{#if position}}<div class=\"side-role\">{{position}}</div>{{/if}}\n                    {{personal_info_html}}\n                </td>\n                <td class=\"main\">\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.554425', '2026-03-19 14:31:20.554425', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (25, '玉砂名片', '米白与玉色卡片组合，整体细腻克制，模块更规整。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f6f3ed; color: #4b4a41; }\n        .resume-shell { background: #fffdfa; border: 1px solid #e5e2d9; }\n        .masthead { padding: 24px 30px; background: #fcfaf5; border-bottom: 1px solid #e5e2d9; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #86a58a; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #2f2e26; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #eff7ef; color: #58705b; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #f7f5ef; border: 1px solid #e5e2d9; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #58705b; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 24px; border: 4px solid #d2e0d0; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #e5e2d9; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #58705b; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #2f2e26; }\n        .item-date { float: right; color: #908c80; font-size: 12px; background: #eff7ef; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #6e6b61; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #4b4a41; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.580073', '2026-03-19 14:31:20.580073', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (26, '琥珀纪事', '琥珀色编辑排版，适合需要兼顾创意与专业感的简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fdf5ea; color: #564331; }\n        .resume-shell { background: #fffefb; border: 1px solid #efe1ca; }\n        .banner { padding: 26px 32px 20px; background: #fff8ef; border-left: 14px solid #cb8a2e; }\n        .banner-label { font-size: 12px; letter-spacing: 5px; color: #94601f; margin-bottom: 8px; }\n        .banner-name { font-size: 33px; font-weight: bold; letter-spacing: 6px; margin: 0 0 8px; color: #392818; }\n        .banner-role { color: #83644a; font-size: 14px; }\n        .body { padding: 22px 32px 28px; }\n        .personal-band { margin-bottom: 18px; padding: 14px 18px; background: #fdf4e7; border-top: 2px solid #cb8a2e; border-bottom: 2px solid #cb8a2e; }\n        .personal-band .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #94601f; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 16px; border: 3px solid #efd0a1; background: #ffffff; }\n        .section { margin-bottom: 18px; padding-left: 16px; border-left: 4px solid #efd0a1; }\n        .section h2 { margin: 0 0 10px; color: #94601f; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #392818; }\n        .item-date { float: right; color: #9f846c; font-size: 12px; }\n        .item-subtitle { color: #83644a; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #564331; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"banner\">\n            <div class=\"banner-label\">EDITORIAL CV</div>\n            <div class=\"banner-name\">{{name}}</div>\n            {{#if position}}<div class=\"banner-role\">应聘职位：{{position}}</div>{{/if}}\n        </div>\n        <div class=\"body\">\n            <div class=\"personal-band\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.598695', '2026-03-19 14:31:20.599717', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (27, '霜白锐线', '大量留白与冷灰线条，整体更像咨询行业使用的职业简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f6f8fa; color: #39434b; }\n        .resume-shell { background: #ffffff; border: 1px solid #e1e6ea; }\n        .hero { padding: 28px 34px 22px; background: #fbfdff; color: #20282f; border-bottom: 4px solid #61717f; }\n        .hero-kicker { font-size: 12px; letter-spacing: 4px; color: #61717f; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 8px; margin: 0 0 8px; text-shadow: 2px 2px 0 #cfd7de; }\n        .hero-role { display: inline-block; padding: 4px 14px; border-radius: 999px; border: 1px solid #61717f; color: #44515c; background: #f2f5f7; font-size: 12px; }\n        .content { padding: 24px 34px 30px; }\n        .personal-card { margin-bottom: 20px; padding: 16px 18px; background: #f7f9fb; border-left: 6px solid #61717f; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #44515c; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 10px; border: 3px solid #cfd7de; background: #ffffff; }\n        .section { margin-bottom: 20px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #e1e6ea; color: #44515c; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #20282f; }\n        .item-date { float: right; color: #82909a; font-size: 12px; background: #f2f5f7; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #5d6a75; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #39434b; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.626991', '2026-03-19 14:31:20.626991', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (28, '海盐画报', '海盐蓝画报风格，双列内容更适合项目经历较多的简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #edf7fa; color: #33515c; }\n        .resume-shell { background: #ffffff; border: 1px solid #d9edf3; }\n        .masthead { padding: 24px 30px; background: #f7fdff; border-bottom: 1px solid #d9edf3; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #4f9bb5; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #1d333b; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #edf9fc; color: #2f7288; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #eff8fb; border: 1px solid #d9edf3; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #2f7288; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #bee0ea; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #d9edf3; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #2f7288; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #1d333b; }\n        .item-date { float: right; color: #7f9aa3; font-size: 12px; background: #edf9fc; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #5a7882; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #33515c; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.638202', '2026-03-19 14:31:20.638202', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (29, '星灰平衡', '低饱和星灰右侧资料栏，阅读稳定，适合多数岗位。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #f4f5f7; color: #3f4652; }\n        .resume-shell { background: #ffffff; border: 1px solid #dde1e8; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .main { width: 68%; padding: 28px 28px 24px; vertical-align: top; }\n        .sidebar { background: #74839a; color: #f6f8fc; padding: 28px 24px; vertical-align: top; }\n        .headline { margin-bottom: 18px; padding-bottom: 12px; border-bottom: 2px solid #c7cfdb; }\n        .headline-kicker { font-size: 12px; color: #74839a; letter-spacing: 4px; margin-bottom: 8px; }\n        .headline-name { font-size: 30px; font-weight: bold; letter-spacing: 7px; margin: 0 0 8px; color: #262b33; }\n        .headline-role { display: inline-block; padding: 4px 12px; border-radius: 999px; background: #f1f4f9; color: #4e5e75; font-size: 12px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #e3e8f1; }\n        .sidebar .personal-value { color: #f6f8fc; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #e3e8f1; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #dde1e8; color: #4e5e75; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #262b33; }\n        .item-date { float: right; color: #89909c; font-size: 12px; }\n        .item-subtitle { color: #626a77; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #3f4652; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"main\">\n                    <div class=\"headline\">\n                        <div class=\"headline-kicker\">PORTFOLIO RESUME</div>\n                        <div class=\"headline-name\">{{name}}</div>\n                        {{#if position}}<div class=\"headline-role\">{{position}}</div>{{/if}}\n                    </div>\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n                <td class=\"sidebar\">\n                    {{personal_info_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.663807', '2026-03-19 14:31:20.663807', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (30, '朝雾双栏', '偏雾感的浅灰蓝双栏布局，适合简洁和理性的风格。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #f2f6f8; color: #3d4f56; }\n        .resume-shell { background: #ffffff; border: 1px solid #dfe8eb; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .sidebar { width: 31%; background: #62818d; color: #f7fbfc; padding: 28px 24px; vertical-align: top; }\n        .main { padding: 28px 28px 24px; vertical-align: top; }\n        .side-kicker { font-size: 12px; letter-spacing: 4px; color: #d9e8ed; margin-bottom: 8px; }\n        .side-name { font-size: 28px; font-weight: bold; letter-spacing: 6px; margin: 0 0 10px; color: #f7fbfc; }\n        .side-role { display: inline-block; padding: 5px 12px; border-radius: 999px; border: 1px solid #d9e8ed; color: #f7fbfc; font-size: 12px; margin-bottom: 18px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #d9e8ed; }\n        .sidebar .personal-value { color: #f7fbfc; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 18px; border: 4px solid #d9e8ed; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-left: 10px; border-left: 5px solid #6f8e9a; color: #4c6973; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #23343a; }\n        .item-date { float: right; color: #87979d; font-size: 12px; }\n        .item-subtitle { color: #607279; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #3d4f56; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"sidebar\">\n                    <div class=\"side-kicker\">SELECTED RESUME</div>\n                    <div class=\"side-name\">{{name}}</div>\n                    {{#if position}}<div class=\"side-role\">{{position}}</div>{{/if}}\n                    {{personal_info_html}}\n                </td>\n                <td class=\"main\">\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.681553', '2026-03-19 14:31:20.681553', 0);
