x 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #67892d; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #2b321e; }\n        .item-date { float: right; color: #96a079; font-size: 12px; background: #f6fce9; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #707a59; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #495039; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.705010', '2026-03-19 14:31:20.705010', 0);
