color: #92797e; font-size: 12px; }\n        .item-subtitle { color: #71585c; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #514143; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"banner\">\n            <div class=\"banner-label\">EDITORIAL CV</div>\n            <div class=\"banner-name\">{{name}}</div>\n            {{#if position}}<div class=\"banner-role\">应聘职位：{{position}}</div>{{/if}}\n        </div>\n        <div class=\"body\">\n            <div class=\"personal-band\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.720752', '2026-03-19 14:31:20.720752', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (33, '远山留白', '冷绿山系留白版式，更适合内容导向、阅读舒适型简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f1f5f2; color: #3f4e43; }\n        .resume-shell { background: #ffffff; border: 1px solid #dde7df; }\n        .hero { padding: 28px 34px 22px; background: #fbfdfb; color: #263026; border-bottom: 4px solid #6f8a78; }\n        .hero-kicker { font-size: 12px; letter-spacing: 4px; color: #6f8a78; margin-bottom: 8px; }\n        .hero-name { font-size: 34px; font-weight: bold; letter-spacing: 8px; margin: 0 0 8px; text-shadow: 2px 2px 0 #d4dfd7; }\n        .hero-role { display: inline-block; padding: 4px 14px; border-radius: 999px; border: 1px solid #6f8a78; color: #4d6655; background: #f5faf6; font-size: 12px; }\n        .content { padding: 24px 34px 30px; }\n        .personal-card { margin-bottom: 20px; padding: 16px 18px; background: #f7fbf7; border-left: 6px solid #6f8a78; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #4d6655; }\n        .personal-photo-wrap { width: 126px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 16px; border: 3px solid #d4dfd7; background: #ffffff; }\n        .section { margin-bottom: 20px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #dde7df; color: #4d6655; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #263026; }\n        .item-date { float: right; color: #879589; font-size: 12px; background: #f5faf6; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #647467; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #3f4e43; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.743403', '2026-03-19 14:31:20.743403', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (34, '柠光矩阵', '浅柠黄点亮分区，整体年轻但不轻浮，适合互联网岗位。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fffef2; color: #504d31; }\n        .resume-shell { background: #ffffff; border: 1px solid #efe9c9; }\n        .masthead { padding: 24px 30px; background: #fffdf6; border-bottom: 1px solid #efe9c9; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #c2b23a; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #302d17; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #fff9cf; color: #8e7f1e; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #fffce6; border: 1px solid #efe9c9; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #8e7f1e; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #eee59f; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #efe9c9; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #8e7f1e; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #302d17; }\n        .item-date { float: right; color: #9d9569; font-size: 12px; background: #fff9cf; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #7a7347; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #504d31; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.757701', '2026-03-19 14:31:20.757701', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (35, '月白长卷', '长卷式清浅版式，信息展开自然，适合经历完整的简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #f5f7fb; color: #434859; }\n        .resume-shell { background: #ffffff; border: 1px solid #e0e5f2; }\n        .masthead { padding: 24px 30px; background: #fbfcff; border-bottom: 1px solid #e0e5f2; }\n        .masthead-kicker { font-size: 12px; letter-spacing: 4px; color: #8599c9; margin-bottom: 8px; }\n        .masthead-name { font-size: 32px; font-weight: bold; letter-spacing: 7px; margin: 0; color: #272b35; }\n        .masthead-role { margin-top: 10px; display: inline-block; padding: 5px 14px; background: #f1f4ff; color: #5c6fa1; border-radius: 999px; font-size: 12px; }\n        .content { padding: 22px 24px 26px; }\n        .personal-card { margin-bottom: 18px; padding: 18px 20px; border-radius: 20px; background: #f7f8fd; border: 1px solid #e0e5f2; }\n        .personal-card .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #5c6fa1; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 22px; border: 4px solid #d3dbf1; background: #ffffff; }\n        .section-grid { width: 100%; border-collapse: separate; border-spacing: 0 16px; }\n        .column { width: 50%; vertical-align: top; padding: 0 8px; }\n        .section { background: #ffffff; border: 1px solid #e0e5f2; border-radius: 18px; padding: 16px 18px; margin-bottom: 0; }\n        .section h2 { margin: 0 0 12px; color: #5c6fa1; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #272b35; }\n        .item-date { float: right; color: #8a90a6; font-size: 12px; background: #f1f4ff; padding: 2px 8px; border-radius: 999px; }\n        .item-subtitle { color: #646a80; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #434859; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n        .summary-wrap .section { margin-top: 16px; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"masthead\">\n            <div class=\"masthead-kicker\">VISUAL RESUME</div>\n            <div class=\"masthead-name\">{{name}}</div>\n            {{#if position}}<div class=\"masthead-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            <table class=\"section-grid\">\n                <tr>\n                    <td class=\"column\">\n                        {{education_html}}\n                        {{experience_html}}\n                    </td>\n                    <td class=\"column\">\n                        {{projects_html}}\n                        {{skills_html}}\n                    </td>\n                </tr>\n            </table>\n            <div class=\"summary-wrap\">{{summary_html}}</div>\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.771039', '2026-03-19 14:31:20.771039', 0);
