}\n        .item-header { width: 100%; }\n        .item-title { font-weight: bold; font-size: 15px; color: #fff7ee; }\n        .item-date { float: right; color: #b69f86; font-size: 12px; background: #3a2f23; padding: 2px 10px; border-radius: 999px; }\n        .item-subtitle { color: #d8c0a4; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #f5ede2; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"hero\">\n            <div class=\"hero-kicker\">CAREER PROFILE</div>\n            <div class=\"hero-name\">{{name}}</div>\n            {{#if position}}<div class=\"hero-role\">{{position}}</div>{{/if}}\n        </div>\n        <div class=\"content\">\n            <div class=\"personal-card\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.785430', '2026-03-19 14:31:20.785430', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (37, '松石侧记', '松石色右侧栏与暖白正文对比明显，适合产品和运营简历。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 22px; background: #eef8f8; color: #345251; }\n        .resume-shell { background: #ffffff; border: 1px solid #d7ecea; }\n        .layout { width: 100%; border-collapse: collapse; }\n        .main { width: 68%; padding: 28px 28px 24px; vertical-align: top; }\n        .sidebar { background: #4d9a96; color: #f4fffd; padding: 28px 24px; vertical-align: top; }\n        .headline { margin-bottom: 18px; padding-bottom: 12px; border-bottom: 2px solid #bfe3e1; }\n        .headline-kicker { font-size: 12px; color: #4d9a96; letter-spacing: 4px; margin-bottom: 8px; }\n        .headline-name { font-size: 30px; font-weight: bold; letter-spacing: 7px; margin: 0 0 8px; color: #1c3332; }\n        .headline-role { display: inline-block; padding: 4px 12px; border-radius: 999px; background: #ecfbfa; color: #2d736f; font-size: 12px; }\n        .sidebar .personal-info { width: 100%; border-collapse: collapse; }\n        .sidebar .personal-meta { vertical-align: top; }\n        .sidebar .personal-row:first-child { display: none; }\n        .sidebar .personal-row { margin: 0 0 10px; font-size: 13px; line-height: 1.75; }\n        .sidebar .personal-label { display: inline-block; min-width: 72px; font-weight: bold; color: #dcf2ef; }\n        .sidebar .personal-value { color: #f4fffd; }\n        .sidebar .personal-photo-wrap { width: 100%; display: block; padding-bottom: 16px; text-align: left; }\n        .sidebar .personal-photo { width: 96px; height: 96px; object-fit: cover; border-radius: 50%; border: 4px solid #dcf2ef; background: #ffffff; }\n        .section { margin-bottom: 18px; }\n        .section h2 { margin: 0 0 12px; padding-bottom: 8px; border-bottom: 1px solid #d7ecea; color: #2d736f; font-size: 17px; letter-spacing: 2px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #1c3332; }\n        .item-date { float: right; color: #7f9b99; font-size: 12px; }\n        .item-subtitle { color: #587776; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #345251; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <table class=\"layout\">\n            <tr>\n                <td class=\"main\">\n                    <div class=\"headline\">\n                        <div class=\"headline-kicker\">PORTFOLIO RESUME</div>\n                        <div class=\"headline-name\">{{name}}</div>\n                        {{#if position}}<div class=\"headline-role\">{{position}}</div>{{/if}}\n                    </div>\n                    {{education_html}}\n                    {{experience_html}}\n                    {{projects_html}}\n                    {{skills_html}}\n                    {{summary_html}}\n                </td>\n                <td class=\"sidebar\">\n                    {{personal_info_html}}\n                </td>\n            </tr>\n        </table>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:20.814353', '2026-03-19 14:31:20.814353', 0);
INSERT INTO `templates_template` (`id`, `name`, `description`, `thumbnail`, `html_content`, `css_content`, `is_active`, `created_at`, `updated_at`, `usage_count`) VALUES (38, '晨曦档案', '晨曦粉橘的档案式排版，兼顾温和质感和清晰层级。', '', '<!DOCTYPE html>\n<html>\n<head>\n    <meta charset=\"UTF-8\" />\n    <style>\n        body { font-family: SimSun, serif; margin: 0; padding: 24px; background: #fff6f1; color: #5a433a; }\n        .resume-shell { background: #fffefd; border: 1px solid #f0ddd6; }\n        .banner { padding: 26px 32px 20px; background: #fffaf7; border-left: 14px solid #d88872; }\n        .banner-label { font-size: 12px; letter-spacing: 5px; color: #ad5f4a; margin-bottom: 8px; }\n        .banner-name { font-size: 33px; font-weight: bold; letter-spacing: 6px; margin: 0 0 8px; color: #3a241d; }\n        .banner-role { color: #8a675d; font-size: 14px; }\n        .body { padding: 22px 32px 28px; }\n        .personal-band { margin-bottom: 18px; padding: 14px 18px; background: #fff5f1; border-top: 2px solid #d88872; border-bottom: 2px solid #d88872; }\n        .personal-band .personal-row:first-child { display: none; }\n        .personal-info { width: 100%; border-collapse: collapse; }\n        .personal-meta { vertical-align: top; }\n        .personal-row { margin: 0 0 8px; font-size: 14px; line-height: 1.8; }\n        .personal-label { display: inline-block; min-width: 92px; font-weight: bold; color: #ad5f4a; }\n        .personal-photo-wrap { width: 120px; text-align: right; vertical-align: top; }\n        .personal-photo { width: 100px; height: 100px; object-fit: cover; border-radius: 16px; border: 3px solid #f4c9bc; background: #ffffff; }\n        .section { margin-bottom: 18px; padding-left: 16px; border-left: 4px solid #f4c9bc; }\n        .section h2 { margin: 0 0 10px; color: #ad5f4a; font-size: 18px; letter-spacing: 3px; }\n        .item { margin-bottom: 14px; }\n        .item-title { font-weight: bold; font-size: 15px; color: #3a241d; }\n        .item-date { float: right; color: #a88980; font-size: 12px; }\n        .item-subtitle { color: #8a675d; font-size: 13px; margin: 4px 0; }\n        .item-content, .skills { color: #5a433a; font-size: 13px; line-height: 1.8; white-space: pre-wrap; }\n    </style>\n</head>\n<body>\n    <div class=\"resume-shell\">\n        <div class=\"banner\">\n            <div class=\"banner-label\">EDITORIAL CV</div>\n            <div class=\"banner-name\">{{name}}</div>\n            {{#if position}}<div class=\"banner-role\">应聘职位：{{position}}</div>{{/if}}\n        </div>\n        <div class=\"body\">\n            <div class=\"personal-band\">{{personal_info_html}}</div>\n            {{education_html}}\n            {{experience_html}}\n            {{projects_html}}\n            {{skills_html}}\n            {{summary_html}}\n        </div>\n    </div>\n</body>\n</html>', '', 1, '2026-03-19 14:31:21.021727', '2026-03-19 14:31:21.021727', 0);

